
-- Clear existing training data to avoid duplicates, then insert fresh comprehensive data
DELETE FROM knowledge_base WHERE category IN ('about', 'pricing', 'features', 'websites', 'expert', 'security', 'faq', 'scenarios', 'general', 'support', 'comparison', 'seo', 'plugins', 'themes', 'domains', 'storage', 'api', 'templates', 'onboarding', 'billing', 'technical');

-- === عن الشركة (15) ===
INSERT INTO knowledge_base (title, content, category, data_type, is_active) VALUES
('تعريف Sity Cloud', 'Sity Cloud هي منصة سحابية متكاملة لإنشاء وإدارة المواقع الإلكترونية. المنصة رقم 1 في العالم العربي لإنشاء المواقع. يثق بنا أكثر من 10,000 عميل ومؤسسة. نوفر محرر مرئي متقدم وقوالب احترافية واستضافة فائقة السرعة.', 'about', 'text', true),
('رسالة الشركة', 'رسالتنا في Sity Cloud هي تمكين كل فرد ومؤسسة في العالم العربي من إنشاء حضورهم الرقمي بسهولة، بدون الحاجة لأي خبرة تقنية. نؤمن إن كل شخص يستحق موقع إلكتروني احترافي.', 'about', 'text', true),
('رؤية الشركة', 'رؤيتنا في Sity Cloud أن نكون المنصة الرائدة في العالم العربي لإنشاء المواقع والتطبيقات، مع تجربة مستخدم استثنائية تناسب الجميع.', 'about', 'text', true),
('تاريخ الشركة', 'بدأت Sity Cloud في 2023 مع فريق صغير متحمس. في 2024 أطلقنا النسخة التجريبية ووصلنا لأول 1000 مستخدم. في 2025 أطلقنا نظام البلجنز والثيمز. في 2026 وصلنا لأكثر من 10,000 موقع و50+ قالب احترافي.', 'about', 'text', true),
('قيم الشركة - البساطة', 'نؤمن في Sity Cloud إن التكنولوجيا لازم تكون بسيطة ومتاحة للجميع. كل أدواتنا مصممة بحيث أي حد يقدر يستخدمها بدون خبرة تقنية.', 'about', 'text', true),
('قيم الشركة - الابتكار', 'نستخدم أحدث تقنيات الذكاء الاصطناعي والتكنولوجيا السحابية لتقديم أفضل تجربة ممكنة لعملائنا. دايماً بنطور ونحسن المنصة.', 'about', 'text', true),
('قيم الشركة - الأمان', 'أمان بيانات عملائنا أولوية قصوى. كل المواقع مؤمنة بشهادة SSL وخوادم محمية مع مراقبة 24/7.', 'about', 'text', true),
('قيم الشركة - الدعم', 'فريق الدعم بتاعنا متاح 24/7 لمساعدة العملاء. بنقدم دعم عربي متخصص بيفهم احتياجات السوق العربي.', 'about', 'text', true),
('أرقام الشركة', 'أكثر من 10,000 موقع تم إنشاؤه على المنصة. أكثر من 50 قالب احترافي متاح. 99.9% وقت التشغيل (uptime). دعم فني متاح 24/7.', 'about', 'text', true),
('فريق العمل', 'فريق Sity Cloud مكون من مطورين ومصممين ومتخصصين في تجربة المستخدم من مختلف أنحاء العالم العربي. بنشتغل كفريق واحد عشان نقدم أفضل منصة.', 'about', 'text', true),
('الموقع الرسمي', 'الموقع الرسمي لـ Sity Cloud هو sity.cloud - تقدر تسجل حساب مجاني وتبدأ تبني موقعك من هناك. رابط التسجيل: sity.cloud/register', 'about', 'text', true),
('طريقة التواصل مع الشركة', 'تقدر تتواصل معانا عن طريق صفحة تواصل معنا على sity.cloud/contact أو عن طريق الواتساب أو عن طريق الإيميل. فريق الدعم متاح 24/7.', 'about', 'text', true),
('Sity Cloud مقابل المنافسين', 'Sity Cloud تتميز عن المنافسين بـ: منشئ مرئي بالسحب والإفلات، ذكاء اصطناعي مدمج، نظام إضافات مفتوح، دعم كامل للغة العربية 100%، استضافة مجانية، SSL مجاني، متجر إلكتروني مدمج، ودعم فني عربي 24/7.', 'about', 'text', true),
('شهادات العملاء', 'أحمد محمد (صاحب متجر إلكتروني): "منصة رائعة! أنشأت متجري بالكامل في ساعتين فقط بدون أي خبرة برمجية." سارة علي (مصممة جرافيك): "أفضل منصة عربية لإنشاء المواقع. القوالب احترافية والدعم ممتاز." خالد عبدالله (مدير شركة): "وفّرنا الكثير من التكاليف بفضل Sity Cloud."', 'about', 'text', true),
('مقر الشركة', 'Sity Cloud شركة تكنولوجيا سحابية بتخدم العالم العربي كله. المنصة متاحة أونلاين من أي مكان في العالم.', 'about', 'text', true),

-- === الباقات والأسعار (20) ===
('الباقة المجانية', 'الباقة المجانية بـ 0 جنيه شهرياً وبتشمل: موقع واحد، 10 صفحات، 1000 ميجا تخزين، إضافتين، ودعم مجتمعي. مناسبة للمبتدئين واللي عايزين يجربوا المنصة.', 'pricing', 'text', true),
('الباقة الاحترافية', 'الباقة الاحترافية بـ 490 جنيه شهرياً وبتشمل: 5 مواقع، 500 صفحة، 50 جيجا تخزين، 10 إضافات، دومين مخصص، دعم تقني، و SSL مجاني. هي الأكثر طلباً ومناسبة للمحترفين والشركات الصغيرة.', 'pricing', 'text', true),
('باقة الأعمال', 'باقة الأعمال بـ 1490 جنيه شهرياً وبتشمل: 25 موقع، 2000 صفحة، 500 جيجا تخزين، 50 إضافة، دومين مخصص، دعم مخصص 24/7، API كامل، ونسخ احتياطي يومي. مناسبة للشركات والمؤسسات الكبيرة.', 'pricing', 'text', true),
('باقة المؤسسات', 'باقة المؤسسات بـ 4990 جنيه شهرياً وبتشمل: مواقع غير محدودة، صفحات غير محدودة، تخزين غير محدود، دعم مخصص VIP، SLA مضمون، تكامل API متقدم، وتقارير متقدمة.', 'pricing', 'text', true),
('خصم الاشتراك السنوي', 'لو اشتركت سنوياً بتوفر 20% من إجمالي الاشتراك. يعني الباقة الاحترافية بدل 490 جنيه شهرياً هتبقى حوالي 392 جنيه شهرياً لو دفعت سنوي.', 'pricing', 'text', true),
('مقارنة الباقات - المواقع', 'المجانية: موقع واحد. الاحترافية: 5 مواقع. الأعمال: 25 موقع. المؤسسات: مواقع غير محدودة.', 'pricing', 'text', true),
('مقارنة الباقات - الصفحات', 'المجانية: 10 صفحات. الاحترافية: 500 صفحة. الأعمال: 2000 صفحة. المؤسسات: صفحات غير محدودة.', 'pricing', 'text', true),
('مقارنة الباقات - التخزين', 'المجانية: 1 جيجا تخزين. الاحترافية: 50 جيجا. الأعمال: 500 جيجا. المؤسسات: تخزين غير محدود.', 'pricing', 'text', true),
('مقارنة الباقات - الإضافات', 'المجانية: إضافتين. الاحترافية: 10 إضافات. الأعمال: 50 إضافة. المؤسسات: إضافات غير محدودة.', 'pricing', 'text', true),
('مقارنة الباقات - الدعم', 'المجانية: دعم مجتمعي. الاحترافية: دعم تقني. الأعمال: دعم مخصص 24/7. المؤسسات: دعم VIP مخصص.', 'pricing', 'text', true),
('العملة والدفع', 'الأسعار بالجنيه المصري. بنقبل الدفع عن طريق بطاقات الائتمان وطرق الدفع المحلية. مفيش رسوم مخفية.', 'pricing', 'text', true),
('الترقية والتخفيض', 'تقدر تغير باقتك في أي وقت من لوحة التحكم. لو رقيت بتتحاسب على الفرق. لو نزلت بتستفيد بالرصيد في الشهور الجاية.', 'pricing', 'text', true),
('ضمان استرداد الأموال', 'بنقدم ضمان استرداد أموال خلال 14 يوم من الاشتراك لو مكنتش راضي عن الخدمة.', 'pricing', 'text', true),
('باقة مخصصة', 'لو عندك احتياجات خاصة مش موجودة في الباقات الحالية، تقدر تتواصل معانا ونعملك باقة مخصصة تناسب احتياجاتك بالظبط.', 'pricing', 'text', true),
('أسعار الدومينات', 'ربط الدومين المخصص متاح من الباقة الاحترافية فما فوق. الدومين نفسه بتشتريه من مزود دومينات وبعدين تربطه بسهولة من لوحة تحكم Sity Cloud.', 'pricing', 'text', true),

-- === المميزات التقنية (25) ===
('Page Builder - محرر الصفحات', 'محرر Sity Cloud بيشتغل بنظام السحب والإفلات (Drag & Drop). تقدر تحرك كل جزء في موقعك بحرية كاملة. مش محتاج أي خبرة برمجية.', 'features', 'text', true),
('الذكاء الاصطناعي المدمج', 'Sity Cloud فيها ذكاء اصطناعي مدمج. وصف فكرتك بالعربي والذكاء الاصطناعي يحولها لصفحة كاملة. يعني تقدر تكتب "عايز صفحة لمطعم" والـ AI يعملها لك.', 'features', 'text', true),
('نظام الثيمات', 'خصص هوية موقعك عبر ثيمات ذكية بألوان وخطوط تليق بعلامتك التجارية. تقدر تغير شكل الموقع كله بضغطة زر.', 'features', 'text', true),
('Header/Footer Builder', 'أنشئ هيدر وفوتر يعكسان شخصية موقعك بالكامل. تحكم كامل في التصميم والمحتوى.', 'features', 'text', true),
('نظام البلوكات', 'بلوكات احترافية جاهزة تقدر تضيفها لموقعك أو تنشئ بلوكاتك الخاصة. توفر وقت كبير في التصميم.', 'features', 'text', true),
('نظام الإضافات (Plugins)', 'فعّل الإضافات اللي تحتاجها فقط بضغطة زر. نظام مفتوح يسمح بتوسيع إمكانيات موقعك حسب احتياجاتك.', 'features', 'text', true),
('SEO - تحسين محركات البحث', 'أدوات SEO مدمجة في المنصة لتحسين ظهور موقعك في نتائج البحث على جوجل. تقدر تعدل العناوين والوصف والكلمات المفتاحية لكل صفحة.', 'features', 'text', true),
('SSL مجاني', 'كل المواقع على Sity Cloud بتحصل على شهادة SSL مجانية. ده بيضمن إن موقعك مشفر وآمن وبيظهر بعلامة القفل الأخضر في المتصفح.', 'features', 'text', true),
('CDN عالمي', 'خوادم سحابية مع شبكة CDN عالمية بتضمن إن موقعك يفتح بسرعة فائقة من أي مكان في العالم.', 'features', 'text', true),
('الاستضافة السحابية', 'استضافة سحابية فائقة السرعة مع ضمان 99.9% وقت تشغيل (uptime). مش محتاج تشتري استضافة من مكان تاني.', 'features', 'text', true),
('ربط الدومين المخصص', 'تقدر تربط دومينك المخصص (زي yoursite.com) بسهولة من لوحة التحكم مع SSL مجاني تلقائي.', 'features', 'text', true),
('المتجر الإلكتروني', 'نظام متجر إلكتروني مدمج في المنصة. تقدر تضيف منتجات وتدير الطلبات وتقبل المدفوعات أونلاين.', 'features', 'text', true),
('نظام المدونة', 'نظام تدوين متكامل. تقدر تنشر مقالات وتنظمها في تصنيفات وتضيف صور ومحتوى غني.', 'features', 'text', true),
('نظام الحجوزات', 'نظام حجوزات ذكي لخدماتك. العملاء يقدروا يحجزوا مواعيد أونلاين وأنت تدير كل حاجة من لوحة التحكم.', 'features', 'text', true),
('النسخ الاحتياطي', 'نسخ احتياطي تلقائي لموقعك. تقدر ترجع لأي نسخة سابقة في أي وقت. النسخ اليومي متاح من باقة الأعمال.', 'features', 'text', true),
('API متقدم', 'تكامل API متقدم متاح من باقة الأعمال. تقدر تربط موقعك مع أي نظام تاني عن طريق الـ API.', 'features', 'text', true),
('التقارير والتحليلات', 'تقارير متقدمة عن زوار موقعك وأداؤه. تقدر تعرف عدد الزوار والصفحات الأكثر زيارة ومصادر الزيارات.', 'features', 'text', true),
('دعم اللغة العربية', 'دعم كامل 100% للغة العربية. كل واجهة المنصة ولوحة التحكم باللغة العربية. دعم RTL كامل لمواقعك.', 'features', 'text', true),
('القوالب الاحترافية', 'أكثر من 50 قالب احترافي جاهز لمختلف المجالات. كل قالب قابل للتخصيص بالكامل حسب احتياجاتك.', 'features', 'text', true),
('النشر بنقرة واحدة', 'بعد ما تخلص تصميم موقعك، تقدر تنشره للعالم بنقرة واحدة. مش محتاج أي إعدادات تقنية معقدة.', 'features', 'text', true),

-- === أنواع المواقع (15) ===
('مواقع الشركات', 'Sity Cloud مثالية لإنشاء مواقع الشركات. تقدر تعرض خدماتك وأعمالك بشكل احترافي مع تصميم يعكس هوية شركتك.', 'websites', 'text', true),
('المتاجر الإلكترونية', 'ابدأ البيع أونلاين مع نظام متجر إلكتروني متكامل. أضف منتجاتك وأدر طلباتك واقبل المدفوعات بسهولة.', 'websites', 'text', true),
('المدونات', 'أنشئ مدونتك وانشر محتواك وابني جمهورك. نظام تدوين متكامل مع دعم SEO وتصنيفات وتعليقات.', 'websites', 'text', true),
('مواقع الحجز', 'أنشئ نظام حجوزات ذكي لخدماتك سواء كنت دكتور أو مدرب أو صالون تجميل أو أي خدمة تحتاج حجز مواعيد.', 'websites', 'text', true),
('مواقع البورتفوليو', 'اعرض أعمالك ومشاريعك بشكل احترافي. مثالي للمصممين والمصورين والمبدعين.', 'websites', 'text', true),
('المواقع التعليمية', 'أنشئ منصة تعليمية وقدم كورساتك أونلاين. نظام إدارة محتوى تعليمي متكامل.', 'websites', 'text', true),
('مواقع المطاعم', 'موقع لمطعمك يعرض المنيو والأسعار ومواعيد العمل مع إمكانية الحجز أونلاين.', 'websites', 'text', true),
('مواقع العقارات', 'اعرض عقاراتك وممتلكاتك بشكل احترافي مع صور وتفاصيل ونظام بحث متقدم.', 'websites', 'text', true),
('مواقع الأطباء والعيادات', 'موقع احترافي لعيادتك يعرض التخصصات ومواعيد العمل مع نظام حجز مواعيد أونلاين.', 'websites', 'text', true),
('المواقع الشخصية', 'أنشئ موقعك الشخصي واعرض سيرتك الذاتية ومهاراتك وأعمالك.', 'websites', 'text', true),
('مواقع الأحداث والفعاليات', 'أنشئ موقع لفعالية أو مؤتمر مع نظام تسجيل وتذاكر أونلاين.', 'websites', 'text', true),
('مواقع الجمعيات والمنظمات', 'موقع احترافي لجمعيتك أو منظمتك يعرض أنشطتك وأهدافك ومشاريعك.', 'websites', 'text', true),
('Landing Pages', 'أنشئ صفحات هبوط احترافية لحملاتك التسويقية. تصميم جذاب مع نموذج تسجيل.', 'websites', 'text', true),
('مواقع وكالات التسويق', 'اعرض خدماتك التسويقية وأعمالك السابقة بشكل يجذب العملاء الجدد.', 'websites', 'text', true),
('مواقع المحامين', 'موقع احترافي لمكتبك القانوني يعرض التخصصات والخبرات مع نموذج استشارة.', 'websites', 'text', true),

-- === Sity Expert (15) ===
('تعريف Sity Expert', 'Sity Expert هي منصة تابعة لـ Sity Cloud متخصصة في تقديم خدمات احترافية. بتوفر خبراء في تصميم المواقع والتسويق الرقمي والبرمجة. الرابط: expert.sity.cloud', 'expert', 'text', true),
('خدمات التصميم في Sity Expert', 'Sity Expert بتقدم خدمات تصميم مواقع احترافية على يد خبراء متخصصين. لو عايز حد يصمم لك موقعك بالكامل، الخبراء بتوعنا يقدروا يساعدوك.', 'expert', 'text', true),
('خدمات التسويق في Sity Expert', 'خبراء التسويق في Sity Expert بيقدروا يساعدوك في إدارة حملاتك التسويقية على السوشيال ميديا وجوجل. من التخطيط للتنفيذ والمتابعة.', 'expert', 'text', true),
('خدمات البرمجة في Sity Expert', 'لو محتاج تطوير مخصص أو إضافات خاصة لموقعك، خبراء البرمجة في Sity Expert يقدروا ينفذوا أي فكرة تقنية.', 'expert', 'text', true),
('التدريب في Sity Expert', 'Sity Expert بتقدم كورسات ودورات تدريبية في تصميم المواقع والتسويق الرقمي والبرمجة. تقدر تتعلم وتطور مهاراتك مع خبراء متخصصين.', 'expert', 'text', true),
('الفريلانس في Sity Expert', 'لو أنت مصمم أو مطور وعايز تشتغل فريلانس، Sity Expert بتوفرلك فرص عمل مع عملاء محتاجين خدماتك.', 'expert', 'text', true),
('المنح والمبادرات', 'Sity Cloud بتقدم منح ومبادرات لدعم رواد الأعمال والشركات الناشئة في العالم العربي. تقدر تتواصل معانا لمعرفة المزيد.', 'expert', 'text', true),
('الشراكات', 'Sity Cloud مفتوحة للشراكات مع شركات التسويق والتصميم ووكالات الويب. بنقدم برنامج شراكة مع عمولات مميزة.', 'expert', 'text', true),
('برنامج الإحالة', 'لو عرفت حد على Sity Cloud واشترك، بتحصل على عمولة. برنامج الإحالة بتاعنا بيكافئك على كل عميل جديد.', 'expert', 'text', true),
('استشارات مجانية', 'Sity Cloud بتقدم استشارات مجانية للعملاء الجدد. لو مش متأكد إيه الباقة المناسبة أو إيه نوع الموقع اللي تحتاجه، كلمنا ونساعدك.', 'expert', 'text', true),
('خدمة تصميم مواقع كاملة', 'لو عايز حد يعمل لك الموقع بالكامل من الألف للياء، Sity Expert بتوفر الخدمة دي. بس قولنا تفاصيل مشروعك وإحنا نقدملك عرض سعر.', 'expert', 'text', true),
('خدمة نقل المواقع', 'لو عندك موقع على منصة تانية وعايز تنقله لـ Sity Cloud، فريقنا يقدر يساعدك في عملية النقل بدون ما تفقد أي بيانات.', 'expert', 'text', true),
('خدمة إدارة المحتوى', 'لو مش عندك وقت تدير محتوى موقعك، Sity Expert بتقدم خدمة إدارة المحتوى. فريقنا يقدر يكتب ويحدث المحتوى بالنيابة عنك.', 'expert', 'text', true),
